class Solution {
public:
    int rearrangeCharacters(string s, string target) {
        int sCount[26] = {0};
        int targetCount[26] = {0};

        for (char c : s) {
            sCount[c - 'a']++;
        }

        for (char c : target) {
            targetCount[c - 'a']++;
        }

        int maxCopies = INT_MAX;
        for (int i = 0; i < 26; i++) {
            if (targetCount[i] != 0) {
                maxCopies = min(maxCopies, sCount[i] / targetCount[i]);
            }
        }

        return maxCopies;
    }
};
```

